INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a208535f-8ca8-4335-a77e-6b73dbb0e18e',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL DataLoader — Batching Resolvers to Kill the N+1 Problem$escape$,
  $escape$Every GraphQL list resolver hides an N+1 trap. Query `posts { author { name } }` with a naive resolver and you'll fire one SQL query per post — 100 posts means 101 queries. DataLoader fixes this by batching all `author` loads within a single tick of the event loop into one `WHERE id = ANY($1)` call. Critically, DataLoader is request-scoped — instantiate it per request inside your context factory, never as a singleton. Each DataLoader takes a batch function that receives an array of keys and must return a same-length, same-order array of values (or Errors). The built-in per-request cache means repeated loads of the same key within a request are deduplicated automatically. For subscriptions, DataLoader doesn't apply the same way — subscription resolvers push events, not pull data, so batch your DB reads before publishing to the PubSub topic. Schema design matters too: expose connection types (`PostConnection`) over plain arrays to make pagination cursor-based, keeping resolver logic predictable and DataLoader batches stable across pages.$escape$,
  $escape$import DataLoader from 'dataloader';
import { pool } from './db';

// Request-scoped context factory
export function createContext(req: Request) {
  const userLoader = new DataLoader<string, User>(async (ids) => {
    const { rows } = await pool.query(
      'SELECT * FROM users WHERE id = ANY($1)',
      [ids]
    );
    // Must return same-order array as input keys
    return ids.map(id => rows.find(r => r.id === id) ?? new Error(`User ${id} not found`));
  });

  return { userLoader };
}

// Resolver
const resolvers = {
  Post: {
    author: (post, _, { userLoader }) => userLoader.load(post.authorId),
  },
};$escape$,
  $escape$typescript$escape$,
