INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fd586cc4-8297-490a-9763-c97a60047688',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL WebSocket Subscriptions — Connection Lifecycle, Heartbeat, and Reconnection with graphql-ws$escape$,
  $escape$GraphQL subscriptions over WebSocket use the `graphql-ws` protocol (not the deprecated `subscriptions-transport-ws`). The lifecycle begins with a `ConnectionInit` message from the client; the server responds with `ConnectionAck` before any `Subscribe` messages are accepted. Each active subscription gets a unique `id` — the server streams `Next` payloads and terminates with `Complete`.

For heartbeats, `graphql-ws` has built-in `Ping`/`Pong` frames. Set `keepAlive` on the server to emit pings at an interval; clients that miss a pong are disconnected, preventing ghost connections.

Reconnection must be handled client-side. The `graphql-ws` `createClient` accepts a `retryAttempts` and `retryWait` function — use exponential backoff here. On reconnect, all active subscriptions are automatically re-sent because `createClient` replays pending `Subscribe` messages.

For rooms (topic isolation), model them as subscription arguments filtered server-side via `withFilter` from `graphql-subscriptions`. The WebSocket connection itself is shared; subscription `id`s act as logical room membership. Never use separate WebSocket connections per room — that defeats multiplexing.$escape$,
  $escape$import { createClient } from 'graphql-ws';

const client = createClient({
  url: 'wss://api.example.com/graphql',
  keepAlive: 10_000, // server must also set keepAlive
  retryAttempts: 5,
  retryWait: async (attempt) => {
    await new Promise(r => setTimeout(r, Math.min(1000 * 2 ** attempt, 30_000)));
  },
  on: {
    connected: () => console.log('ConnectionAck received'),
    closed: (e) => console.warn('WS closed', e),
    ping: (received) => console.debug(received ? 'Pong sent' : 'Ping sent'),
  },
});

// Subscribe to a "room" via argument
const unsub = client.subscribe(
  { query: 'subscription($room: ID!) { messages(roomId: $room) { id text } }', variables: { room: 'room-42' } },
  { next: (data) => console.log(data), error: console.error, complete: () => console.log('done') }
);

// Cleanup
unsub();$escape$,
