INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7f1d609-4b1d-4912-b239-9829390730e8',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL Developer's Guide to tRPC — Type Safety Without the SDL$escape$,
  $escape$tRPC delivers end-to-end type safety without GraphQL's SDL, resolvers, or codegen pipeline. Where you'd define types in SDL and run GraphQL Code Generator to sync them to TypeScript, tRPC infers client types directly from server-side procedure definitions — zero generation step.

Procedures map cleanly to GraphQL operations: `query` for reads, `mutation` for writes, `subscription` for streaming. Each procedure uses Zod for input validation — analogous to GraphQL input types — and the return type is inferred automatically. No `__typename` juggling, no fragment management, no `DocumentNode` identity issues.

React Query integration via `@trpc/react-query` mirrors Apollo Client's `useQuery`/`useMutation` API surface. `trpc.getUser.useQuery({ id })` generates a fully typed React Query hook — cache keys are derived automatically from the procedure name and input, unlike Apollo where you manage document identity manually.

The tradeoff is real: tRPC is TypeScript-only and monorepo-bound, while GraphQL is language-agnostic and excels at federated APIs across teams. If your stack is Next.js + TypeScript with no external API consumers, tRPC eliminates the SDL-to-type sync overhead entirely.$escape$,
  $escape$// server/router.ts — replaces SDL + resolvers
const appRouter = router({
  getUser: publicProcedure
    .input(z.object({ id: z.string() }))
    .query(({ input }) => db.users.findById(input.id)),

  createUser: publicProcedure
    .input(z.object({ name: z.string(), email: z.string().email() }))
    .mutation(({ input }) => db.users.create(input)),
});

export type AppRouter = typeof appRouter;

// client — no DocumentNode, no codegen
const { data } = trpc.getUser.useQuery({ id: "123" });
// data: Awaited<ReturnType<typeof db.users.findById>>$escape$,
  $escape$typescript$escape$,
