INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81962f41-b685-400c-9fbc-b81106c6325a',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL API Versioning — Why You Probably Don't Need /v2$escape$,
  $escape$GraphQL's type system is designed for evolution, not versioning. URL versioning (/v1/graphql, /v2/graphql) forces clients to migrate entire schemas at once — the opposite of GraphQL's additive model. Header versioning (X-Api-Version: 2) is marginally better but still creates schema forks you must maintain in parallel.

The idiomatic path is schema evolution with @deprecated. Add new fields freely — GraphQL is additive by default. Mark old fields deprecated with a reason, give clients a migration window, then remove them in a future release. Introspection lets clients detect deprecated fields programmatically.

For genuinely breaking changes — renaming a type, changing an argument from optional to required, altering a scalar — use a field alias pattern: keep the old field, introduce the new one with a clearer name, deprecate the old. If you truly need hard versioning (e.g. a public API with SLA guarantees), run two separate schema endpoints rather than multiplexing version logic inside a single resolver graph. Tools like GraphQL Inspector can diff schemas and flag breaking changes in CI before they reach production.$escape$,
  $escape$# schema.graphql
type Query {
  # deprecated: use userProfile(id: ID!) instead
  user(id: ID!): User @deprecated(reason: "Use userProfile — returns richer type")
  userProfile(id: ID!): UserProfile
}

type User {
  name: String
  email: String @deprecated(reason: "Use UserProfile.contactEmail")
}

type UserProfile {
  displayName: String
  contactEmail: String
  avatarUrl: String
}$escape$,
  $escape$graphql$escape$,
