INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8358a906-cafc-4c9e-9ba6-0617e04ded71',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL Authentication — JWT, API Keys, and Context Propagation$escape$,
  $escape$GraphQL has no built-in auth layer — authentication lives outside the schema, in your server's context factory. Every resolver receives a `context` object built per-request, making it the canonical place to validate credentials and attach the caller's identity.

For JWT (OAuth2 Bearer), extract and verify the token in the context builder before any resolver runs. If verification fails, set `user: null` — don't throw yet. Let resolvers or a schema directive like `@authenticated` decide the response. This keeps auth logic centralized and testable independently of business logic.

For API keys, the same pattern applies: read `x-api-key` from headers in context, look up the key, and attach the associated principal.

mTLS is handled at the transport layer (reverse proxy or server TLS config), but the client certificate's subject can be forwarded via a trusted header (`x-client-cert-dn`) and consumed in the same context pipeline.

Never do auth inside individual resolvers — it creates inconsistent enforcement. Use a field middleware or schema directive to declaratively protect types and fields uniformly.$escape$,
  $escape$import { ApolloServer } from '@apollo/server';
import { expressMiddleware } from '@apollo/server/express4';
import jwt from 'jsonwebtoken';

const server = new ApolloServer({ typeDefs, resolvers });

app.use('/graphql', expressMiddleware(server, {
  context: async ({ req }) => {
    const token = req.headers.authorization?.replace('Bearer ', '');
    const apiKey = req.headers['x-api-key'];

    if (token) {
      try {
        const user = jwt.verify(token, process.env.JWT_SECRET!);
        return { user };
      } catch {
        return { user: null };
      }
    }

    if (apiKey) {
      const user = await lookupApiKey(apiKey);
      return { user };
    }

    return { user: null };
  },
}));$escape$,
  $escape$typescript$escape$,
