INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '91f1158e-56cc-4190-bdfb-aa8c46b516a2',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL SDL-First vs Code-First — Picking Your Schema Strategy$escape$,
  $escape$GraphQL's equivalent of OpenAPI's spec-first vs code-first debate is SDL-first vs code-first schema design. SDL-first means your `.graphql` files are the source of truth — resolvers are typed against them via tooling like `graphql-codegen`. Code-first (Nexus, TypeGraphQL, Pothos) derives the SDL from your TypeScript resolver definitions at runtime, so the schema is a build artifact, not a committed file.

SDL-first wins on contract stability: the schema is a versioned artifact any team can diff in PRs, and `@graphql-codegen/client-preset` reads it alongside your operation documents to emit fully-typed React hooks for Apollo Client or urql — zero hand-written types. Code-first wins on refactoring ergonomics: rename a field in TypeScript and the schema updates automatically, eliminating dual-maintenance drift.

Documentation is intrinsic to GraphQL. Any field annotated with a triple-quoted `"""` description is surfaced automatically in GraphiQL, Apollo Studio, and Altair — no separate OpenAPI YAML to maintain. For public or multi-client APIs, SDL-first is the safer default. For backend-internal schemas that churn frequently, code-first reduces overhead.$escape$,
  $escape$// codegen.ts — SDL-first client generation with graphql-codegen
import type { CodegenConfig } from '@graphql-codegen/cli';

const config: CodegenConfig = {
  schema: './schema.graphql',
  documents: ['src/**/*.graphql'],
  generates: {
    './src/gql/': {
      preset: 'client',
      config: {
        strictScalars: true,
        scalars: { DateTime: 'string' },
      },
    },
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
