INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f764fd81-3026-4559-99d5-22b196001526',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL Rate Limiting — Per-Field Sliding Windows vs Token Buckets$escape$,
  $escape$GraphQL's flexible query structure makes naive REST-style rate limiting ineffective. A single POST to `/graphql` can trigger 1 or 100 resolver calls — limiting by HTTP request count is meaningless.

For per-field limiting, attach rate limit logic inside individual resolvers or via a schema directive like `@rateLimit`. Libraries such as `graphql-rate-limit` let you configure limits per field per user using a sliding window: each request logs a timestamp, and the count of requests within the last N seconds is checked against a threshold. Sliding windows smooth out burst behavior but require storing per-user timestamp arrays in Redis.

Token bucket suits bursty-but-bounded traffic better. Each user starts with N tokens; each resolver invocation costs tokens; tokens replenish at a fixed rate. This allows short bursts while enforcing long-run averages — ideal for clients running complex nested queries.

For per-user isolation, key your store on `context.user.id + fieldName`. With `graphql-shield`, compose rate limit rules directly into your permission layer so they run before resolvers execute, avoiding wasted compute on blocked requests.$escape$,
  $escape$import { createRateLimitRule } from 'graphql-rate-limit';
import { shield, and } from 'graphql-shield';

const rateLimitRule = createRateLimitRule({
  identifyContext: (ctx) => ctx.user.id,
  store: new RedisStore(redisClient),
});

const permissions = shield({
  Query: {
    // Sliding window: 10 calls per user per 60s on this field
    searchPosts: and(
      isAuthenticated,
      rateLimitRule({ window: '60s', max: 10 })
    ),
  },
  Mutation: {
    // Stricter limit on expensive mutations
    generateAISummary: rateLimitRule({ window: '60s', max: 3 }),
  },
});$escape$,
