INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1f20f86a-6e33-4ffd-a329-70bb8baeffdb',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL Contract Testing — Lock Down Your Schema with MSW and graphql-codegen$escape$,
  $escape$GraphQL's typed schema is a contract. Break it silently and every client breaks with it. Contract testing enforces that contract before a breaking change ships.

Use `graphql-codegen` to generate TypeScript types from your SDL, then drive your MSW mock server with those exact types. Any resolver returning a shape that doesn't satisfy the generated type fails at compile time — before a single integration test runs.

For integration tests, skip REST-style HTTP interceptors. Use `graphql-request` or Apollo Client's `MockedProvider` directly against a real in-memory `graphql` execution engine built with `makeExecutableSchema` from `@graphql-tools/schema`. This tests the full resolver chain — arguments, context injection, error propagation — without a network hop.

For mutation contract tests, assert on the exact `errors` array shape, not just `data`. GraphQL returns HTTP 200 even on partial failures; your test suite must check `data === null` and `errors[0].extensions.code` explicitly. Use `graphql-tag` to parse queries at test time so any syntax error surfaces immediately, not at runtime.$escape$,
  $escape$import { makeExecutableSchema } from '@graphql-tools/schema';
import { graphql } from 'graphql';
import { typeDefs } from '../schema';
import { resolvers } from '../resolvers';

const schema = makeExecutableSchema({ typeDefs, resolvers });

it('returns null data and UNAUTHENTICATED code on missing token', async () => {
  const result = await graphql({
    schema,
    source: `query { me { id email } }`,
    contextValue: { user: null },
  });

  expect(result.data?.me).toBeNull();
  expect(result.errors?.[0].extensions?.code).toBe('UNAUTHENTICATED');
});$escape$,
