INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '025b22db-bf87-4c07-8f7f-981e615dd988',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL HTTP Caching — APQ, Cache-Control, and ETags Without Breaking POST Semantics$escape$,
  $escape$GraphQL's single POST `/graphql` endpoint is a CDN dead zone — HTTP caches don't cache POST responses by definition. The escape hatch: send read operations as GET requests via Automatic Persisted Queries (APQ). The client hashes the query with SHA-256 and sends only the hash as a GET parameter. On a miss, the server returns `PersistedQueryNotFound`; the client retries with the full query body, the server registers the hash, and future requests use the short cacheable URL.

Apollo Server's `@cacheControl` directive lets you annotate fields individually. The plugin computes the minimum `maxAge` across all resolved fields in the response tree and writes a single `Cache-Control` header — so one uncacheable field (`maxAge: 0`) poisons the whole response. Mark user-specific fields `scope: PRIVATE` to block CDN storage while still allowing browser caching.

For ETags, `@apollo/server-plugin-response-cache` hashes the full response and emits an `ETag` header. On repeated GET requests with `If-None-Match`, the plugin short-circuits resolver execution entirely and returns `304 Not Modified` — no DB round-trip, no resolver overhead.$escape$,
  $escape$import { ApolloServer } from '@apollo/server';
import { ApolloServerPluginCacheControl } from '@apollo/server/plugin/cacheControl';
import responseCachePlugin from '@apollo/server-plugin-response-cache';

const typeDefs = `#graphql
  type Query {
    feed: [Post!]! @cacheControl(maxAge: 30, scope: PUBLIC)
    me: User       @cacheControl(maxAge: 0,  scope: PRIVATE)
  }
`;

const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [
    ApolloServerPluginCacheControl({ defaultMaxAge: 0 }),
    responseCachePlugin(),
  ],
});$escape$,
