INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '00ee5e0b-9654-4a1c-bcab-bf4d5a6a0f35',
  '00000000-0000-0000-0000-000000000001',
  $escape$GraphQL Error Extensions — Enforcing a problem+json Contract in Every Response$escape$,
  $escape$GraphQL's `errors` array is spec-defined, but `extensions` is your escape hatch for structured metadata. Instead of leaking raw messages or scattering ad-hoc codes, mirror RFC 7807's problem+json shape inside `extensions`: a `type` URI identifying the error class, `title` for human-readable category, `detail` for instance-specific context, and `status` for HTTP consumers bridging to REST. Apollo Server's `formatError` hook is where you enforce this contract — inspect each `GraphQLError`, check its `originalError`, then stamp normalized extensions before serialization. This matters because GraphQL runs over HTTP *and* WebSocket (subscriptions); clients shouldn't need protocol-specific error-parsing branches. A shared shape enforced in `formatError` guarantees every error surface — resolvers, auth directives, DataLoader callbacks — emits the same structure. Treat missing `type` URIs as a contract violation. Errors without them are debugging black holes; extensions are a first-class API surface, not an afterthought.$escape$,
  $escape$import { ApolloServer, GraphQLError } from '@apollo/server';

const server = new ApolloServer({
  typeDefs,
  resolvers,
  formatError(formattedError) {
    const ext = formattedError.extensions ?? {};
    return {
      ...formattedError,
      extensions: {
        type: ext.type ?? 'https://errors.example.dev/internal',
        title: ext.title ?? 'Internal Server Error',
        detail: formattedError.message,
        status: ext.status ?? 500,
      },
    };
  },
});

// In a resolver:
throw new GraphQLError('User not found', {
  extensions: { type: 'https://errors.example.dev/not-found', title: 'Not Found', status: 404 },
});$escape$,
  $escape$typescript$escape$,
